parameters.jsCode:
const source = $items('Normalize Typebot Input')[0]?.json ?? {};
const rawItems = $input.all();
const question = String(source.question ?? '').trim();
const locale = String(source.locale ?? '').trim().toLowerCase();
const signal = [question, locale, source.category ?? ''].join(' ');
const outOfDomain = /날씨|강수|기온|weather|rain probability|thời\s*tiết|khả\s*năng\s*mưa|nhiệt\s*độ|цаг\s*агаар|бороо|температур/iu.test(signal);
const attachments = Array.isArray(source.attachments) ? source.attachments.slice(0, 3) : [];
const attachmentContext = attachments.map((file, index) => [`[ATTACHMENT ${index + 1}]`, `name: ${String(file.name ?? 'attachment')}`, `type: ${String(file.type ?? '')}`, `document_type: ${String(file.documentType ?? 'unknown')}`, 'extracted_text:', String(file.extractedText ?? '').slice(0, 6000)].join('\n')).join('\n\n');

function text(value) {
  return String(value ?? '').trim();
}

function firstText(...values) {
  for (const value of values) {
    const resolved = text(value);
    if (resolved) return resolved;
  }
  return null;
}

function numberOrNull(value) {
  if (value === null || value === undefined || String(value).trim() === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function round(value) {
  const n = numberOrNull(value);
  return n === null ? null : Number(n.toFixed(4));
}

const SUPPORTED_LOCALES = new Set(['ko', 'en', 'vi', 'mn']);
const requestedLocale = SUPPORTED_LOCALES.has(locale) ? locale : 'ko';
const HANGUL_RE = /[가-힣ㄱ-ㅎㅏ-ㅣ]/u;
const CYRILLIC_RE = /[А-Яа-яЁёӨөҮү]/u;
const VIETNAMESE_RE = /[ăâđêôơưàáảãạằắẳẵặầấẩẫậèéẻẽẹềếểễệìíỉĩịòóỏõọồốổỗộờớởỡợùúủũụừứửữựỳýỷỹỵ]/iu;
const LATIN_RE = /[a-z]/iu;
const VIETNAMESE_WORD_RE = /(?:^|\s)(?:hồ\s*sơ|chi\s*phí|du\s*học|tài\s*chính|thị\s*thực|tổng\s*quan|gia\s*hạn|sinh\s*viên|trường|căn\s*cứ)(?:\s|$)/iu;
const FALLBACK_TITLES = {
  ko: 'KAXI 승인 문서',
  en: 'KAXI approved source',
  vi: 'Nguồn KAXI đã duyệt',
  mn: 'KAXI баталгаажсан эх сурвалж',
};
const CATEGORY_SCOPES = {
  cost: ['cost'],
  visa: ['visa', 'legal', 'process', 'warning'],
  documents: ['documents', 'legal', 'process', 'warning'],
  school: ['school', 'documents', 'process'],
  warning: ['warning', 'legal'],
  process: ['process', 'warning', 'legal'],
  legal: ['legal'],
};

function normalizeLocale(value) {
  const normalized = text(value).toLowerCase();
  if (normalized === 'kr' || normalized === 'ko-kr') return 'ko';
  if (normalized === 'vn' || normalized === 'vi-vn') return 'vi';
  if (normalized === 'en-us' || normalized === 'en-gb') return 'en';
  if (normalized === 'mn-mn') return 'mn';
  return SUPPORTED_LOCALES.has(normalized) ? normalized : null;
}

function scriptFlags(value) {
  const candidate = text(value);
  return {
    hangul: HANGUL_RE.test(candidate),
    cyrillic: CYRILLIC_RE.test(candidate),
    vietnamese: VIETNAMESE_RE.test(candidate),
    latin: LATIN_RE.test(candidate),
  };
}

function detectTextLocale(value) {
  const flags = scriptFlags(value);
  if (flags.hangul) return 'ko';
  if (flags.vietnamese) return 'vi';
  if (flags.cyrillic) return 'mn';
  if (flags.latin) return 'en';
  return null;
}

function firstHeading(value) {
  const heading = text(value).split(/\r?\n/).find((line) => /^#{1,6}\s+/.test(line));
  return heading ? heading.replace(/^#{1,6}\s+/, '').trim() : null;
}

function withoutNeutralTerms(value) {
  return text(value)
    .replace(/\b(?:[cdef]-?\d+(?:-\d+)?|topik|kaxi|hikorea|kiip|arc|k-eta|krw|usd|pdf)\b/giu, ' ')
    .replace(/[\d\s.,:;()[\]{}\/_+&-]+/g, ' ')
    .trim();
}

function titleMatchesLocale(value) {
  const title = text(value).replace(/^#{1,6}\s+/, '').trim();
  if (!title) return false;
  const candidate = withoutNeutralTerms(title);
  const flags = scriptFlags(candidate);
  if (requestedLocale === 'ko') {
    return flags.hangul && !flags.cyrillic && !flags.vietnamese && !flags.latin;
  }
  if (requestedLocale === 'en') {
    return flags.latin && !flags.hangul && !flags.cyrillic && !flags.vietnamese;
  }
  if (requestedLocale === 'vi') {
    return (flags.vietnamese || VIETNAMESE_WORD_RE.test(candidate))
      && !flags.hangul
      && !flags.cyrillic;
  }
  return flags.cyrillic && !flags.hangul && !flags.vietnamese && !flags.latin;
}

function resolveLocalizedTitle(pageContent, metadataTitle) {
  const headings = text(pageContent)
    .split(/\r?\n/)
    .filter((line) => /^#{1,6}\s+/.test(line))
    .map((line) => line.replace(/^#{1,6}\s+/, '').trim());
  const candidate = [...headings, text(metadataTitle)].find((value) => titleMatchesLocale(value));
  return candidate || FALLBACK_TITLES[requestedLocale];
}

function contentMatchesLocale(value, metadata) {
  const content = text(value);
  if (!content) return false;
  const reported = [metadata.language, metadata.locale_filter, metadata.locale]
    .map(normalizeLocale)
    .filter(Boolean);
  if (reported.some((language) => language !== requestedLocale)) return false;

  const detected = detectTextLocale(firstHeading(content) || content);
  if (detected !== requestedLocale) return false;

  const flags = scriptFlags(content);
  if (requestedLocale === 'ko') return !flags.cyrillic && !flags.vietnamese;
  if (requestedLocale === 'en') return !flags.hangul && !flags.cyrillic && !flags.vietnamese;
  if (requestedLocale === 'vi') return !flags.hangul && !flags.cyrillic && (flags.vietnamese || VIETNAMESE_WORD_RE.test(content));
  return !flags.hangul && !flags.vietnamese && flags.cyrillic;
}

function tokenize(value) {
  const stopWords = new Set([
    'the', 'and', 'for', 'with', 'from', 'that', 'this', 'what', 'how',
    '한국', '유학', '관련', '대해', '알려주세요', '문의',
    'các', 'cho', 'với', 'này', 'được', 'hãy',
    'ямар', 'тухай', 'болон', 'энэ', 'хэрхэн',
  ]);
  return (text(value).normalize('NFKC').toLowerCase().match(/[\p{L}\p{N}][\p{L}\p{N}-]*/gu) || [])
    .filter((token) => token.length >= 2 && !stopWords.has(token));
}

function tokenOverlap(queryTokens, candidateTokens) {
  if (queryTokens.length === 0 || candidateTokens.length === 0) return 0;
  const matched = queryTokens.filter((queryToken) => candidateTokens.some(
    (candidateToken) => candidateToken === queryToken
      || candidateToken.includes(queryToken)
      || queryToken.includes(candidateToken),
  ));
  return matched.length / queryTokens.length;
}

const queryTokens = tokenize(question);

function categoryRerankBoost(candidateCategory) {
  const requestedCategory = text(source.category || 'general').toLowerCase();
  const candidate = text(candidateCategory || 'general').toLowerCase();
  if (!requestedCategory || requestedCategory === 'general') return 0;
  if (candidate === requestedCategory) return 0.18;
  if ((CATEGORY_SCOPES[requestedCategory] || []).includes(candidate)) return 0.08;
  return -0.5;
}

function rerankDocument(doc, originalIndex) {
  const bodyTokens = tokenize([doc.title, doc.pageContent, doc.metadata.keywords || ''].join(' '));
  const titleTokens = tokenize(doc.title);
